import React, { useState } from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox";
import { FaProjectDiagram } from "react-icons/fa";
import { motion } from "framer-motion"; // Import motion for better animation

const AppLayout = ({ children }) => {
  const [showLogin, setShowLogin] = useState(false);

  const toggleLogin = () => {
    setShowLogin(!showLogin);
  };

  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-64 bg-gray-900 text-white">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative">
        {/* Header */}
        <motion.header
          className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-4 px-6 shadow-lg w-full text-center flex flex-col items-center"
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, ease: "easeOut" }}
        >
          <FaProjectDiagram className="text-4xl text-yellow-300 mb-1" />
          <h1 className="text-xl font-semibold tracking-wide">
            🚀 Manage Your Projects With
          </h1>
          <h2 className="text-3xl font-extrabold text-yellow-300">Proma</h2>
        </motion.header>

        {/* Login Button */}
        <div className="absolute top-4 right-6">
          <button
            onClick={toggleLogin}
            className="bg-yellow-400 text-black px-4 py-2 rounded-lg font-semibold hover:bg-yellow-500 transition"
          >
            Login
          </button>
        </div>

        {/* Page Content */}
        <div className="p-6">{children}</div>

        {/* Login Box Popup */}
        {showLogin && (
          <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
            <div className="bg-white p-5 rounded-lg shadow-xl relative w-96">
              <button
                onClick={toggleLogin}
                className="absolute top-2 right-3 text-gray-700 hover:text-gray-900 text-xl"
              >
                ✖
              </button>
              <LoginBox />
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AppLayout;
